import { createHash } from "crypto";
function computeIntegritySignature(reference, amountInCents, currency, secret) {
  return createHash("sha256").update(`${reference}${amountInCents}${currency}${secret}`).digest("hex");
}
function buildCheckoutUrl(params) {
  const sig = computeIntegritySignature(
    params.reference,
    params.amountInCents,
    params.currency,
    params.integritySecret
  );
  const u = new URL("https://checkout.wompi.co/p/");
  u.searchParams.set("public-key", params.publicKey);
  u.searchParams.set("currency", params.currency);
  u.searchParams.set("amount-in-cents", String(params.amountInCents));
  u.searchParams.set("reference", params.reference);
  u.searchParams.set("redirect-url", params.redirectUrl);
  u.searchParams.set("signature:integrity", sig);
  return u.toString();
}
function resolvePath(obj, path) {
  return path.split(".").reduce((acc, key) => {
    if (acc && typeof acc === "object" && key in acc) {
      return acc[key];
    }
    return void 0;
  }, obj);
}
function verifyWebhookSignature(payload, eventsSecret) {
  const parts = [];
  for (const prop of payload.signature.properties) {
    const v = resolvePath(payload.data, prop);
    if (v === void 0 || v === null) return false;
    parts.push(String(v));
  }
  const raw2 = parts.join("") + String(payload.timestamp) + eventsSecret;
  const computed = createHash("sha256").update(raw2).digest("hex");
  return computed === payload.signature.checksum;
}
function computeNewPaidUntil(current, product, now = Date.now()) {
  const base = Math.max(now, current.paidUntil ?? 0);
  return base + product.durationDays * 864e5;
}

// src/lib/wallet.ts
function applyDiscount(priceCop, discountPercent) {
  const pct = discountPercent ?? 0;
  return Math.round(priceCop * (1 - pct / 100));
}

